# --- Build a random ill-conditioned 6x6 matrix ---
n = 6
U, _, Vt = np.linalg.svd(np.random.randn(n, n))
# Singular values spanning several orders of magnitude -> ill-conditioned
singular_values = np.array([1e4, 1e3, 1e2, 1e1, 1e0, 1e-1])
A = U @ np.diag(singular_values) @ Vt

# --- Initial approximation V0 = alpha * A^T ---
norm1   = np.linalg.norm(A, 1)
norminf = np.linalg.norm(A, np.inf)
alpha   = 1.0 / (norm1 * norminf)
V0      = alpha * A.T

I = np.eye(n)
iterations = 8

def residual(A, V):
    return np.linalg.norm(I - A @ V)

# -- Method 1: Hotelling-Bodewig (2nd order) --
def hotelling_bodewig(A, V0, iters):
    V = V0.copy()
    errs = [residual(A, V)]
    for _ in range(iters):
        V = V @ (2*I - A @ V)
        errs.append(residual(A, V))
    return errs

# -- Method 2: Li et al. 3rd-order --
def li_third_order(A, V0, iters):
    V = V0.copy()
    errs = [residual(A, V)]
    for _ in range(iters):
        AV = A @ V
        V  = V @ (3*I - AV @ (3*I - AV))
        errs.append(residual(A, V))
    return errs

# -- Method 3: Soleymani 7th-order --
# Geometric-series accelerator: V_{n+1} = V_n * (I + E + E^2 + ... + E^6)
def soleymani_seventh_order(A, V0, iters):
    V = V0.copy()
    errs = [residual(A, V)]
    for _ in range(iters):
        E  = I - A @ V
        E2 = E  @ E
        E3 = E2 @ E
        E4 = E3 @ E
        E5 = E4 @ E
        E6 = E5 @ E
        V  = V @ (I + E + E2 + E3 + E4 + E5 + E6)
        errs.append(residual(A, V))
    return errs

errs_hb  = hotelling_bodewig(A, V0, iterations)
errs_li  = li_third_order(A, V0, iterations)
errs_sol = soleymani_seventh_order(A, V0, iterations)

